// Move an actor along a spline over time
UPROPERTY(EditAnywhere)
USplineComponent* PathSpline;

float CurrentDistance = 0.f;
float MoveSpeed = 200.f;

void AMyMovingPlatform::Tick(float DeltaTime) {
    Super::Tick(DeltaTime);

    CurrentDistance += MoveSpeed * DeltaTime;
    float SplineLength = PathSpline->GetSplineLength();

    // Loop
    if (CurrentDistance > SplineLength) CurrentDistance -= SplineLength;

    FVector NewLoc = PathSpline->GetLocationAtDistanceAlongSpline(CurrentDistance, ESplineCoordinateSpace::World);
    FRotator NewRot = PathSpline->GetRotationAtDistanceAlongSpline(CurrentDistance, ESplineCoordinateSpace::World);

    SetActorLocationAndRotation(NewLoc, NewRot);
}

// Spawn meshes along a spline (fence posts)
void AMyFence::BuildFence() {
    float Spacing = 200.f;
    float Length = SplineComp->GetSplineLength();

    for (float Dist = 0.f; Dist < Length; Dist += Spacing) {
        FVector Loc = SplineComp->GetLocationAtDistanceAlongSpline(Dist, ESplineCoordinateSpace::World);
        FRotator Rot = SplineComp->GetRotationAtDistanceAlongSpline(Dist, ESplineCoordinateSpace::World);

        UStaticMeshComponent* Post = NewObject<UStaticMeshComponent>(this);
        Post->SetStaticMesh(FencePostMesh);
        Post->SetWorldLocationAndRotation(Loc, Rot);
        Post->RegisterComponent();
    }
}
